    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle sensor timeout first - go to safe idle */
    if (controller->has_valid_temperature == false || controller->has_valid_level == false) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* If either sensor becomes stale for more than 1000 ms, go to safe idle */
    if (input.now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS ||
        input.now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Update valid state flags */
    controller->has_valid_temperature = true;
    controller->has_valid_level = true;

    /* Handle temperature update */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
    }

    /* Handle level update */
    if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }

    /* Control policy:
     * - If LEVEL < 60, command INLET OPEN and HEATER OFF (FILLING state)
     * - If LEVEL > 75, command INLET CLOSED (HOLDING or SAFE_IDLE depending on temperature)
     * - If LEVEL < 55 at any time, keep HEATER OFF
     * - If 60 <= LEVEL <= 75 and TEMP < 45, command INLET CLOSED and HEATER ON (HEATING state)
     * - If 45 <= TEMP < 47, command INLET CLOSED and hold previous safe heater state (HOLDING state)
     * - If 47 <= TEMP <= 48 and temperature is rising compared with the previous valid temperature sample, command HEATER OFF early (HEATING state with heater off)
     * - If 47 <= TEMP <= 48 and temperature is not rising, hold the previous safe heater state (HOLDING state)
     * - If TEMP > 48, command INLET CLOSED and HEATER OFF (HOLDING state)
     */

    /* Determine current action based on level and temperature */
    bool inlet_open = false;
    bool heater_on = false;
    controller_state_t current_state = CONTROLLER_STATE_SAFE_IDLE;

    if (input.level < 60) {
        /* Level too low - fill the tank */
        inlet_open = true;
        heater_on = false;
        current_state = CONTROLLER_STATE_FILLING;
    } else if (input.level > 75) {
        /* Level too high - close inlet */
        inlet_open = false;
        heater_on = false;
        /* Determine holding state based on temperature */
        if (controller->last_temperature_c < 45) {
            current_state = CONTROLLER_STATE_SAFE_IDLE;
        } else {
            current_state = CONTROLLER_STATE_HOLDING;
        }
    } else {
        /* Level is safe for heating, but check temperature conditions */
        heater_on = false;

        if (input.temperature_c < 45) {
            /* Low temperature - close inlet and heat */
            inlet_open = false;
            heater_on = true;
            current_state = CONTROLLER_STATE_HEATING;
        } else if (input.temperature_c >= 47 && input.temperature_c <= 48) {
            /* Near upper band with rising temp - shut off heater early */
            if (controller->last_temperature_ms > controller->previous_temperature_c) {
                /* Temperature is rising */
                inlet_open = false;
                heater_on = false;
                current_state = CONTROLLER_STATE_HEATING;
            } else {
                /* Temperature is not rising - hold previous heater state */
                inlet_open = false;
                heater_on = controller->heater_on;
                current_state = CONTROLLER_STATE_HOLDING;
            }
        } else if (input.temperature_c > 48) {
            /* High temperature - close inlet and turn off heater */
            inlet_open = false;
            heater_on = false;
            current_state = CONTROLLER_STATE_HOLDING;
        } else {
            /* 45 <= TEMP < 47 - close inlet, hold previous heater state */
            inlet_open = false;
            heater_on = controller->heater_on;
            current_state = CONTROLLER_STATE_HOLDING;
        }
    }

    output.inlet_open = inlet_open;
    output.heater_on = heater_on;
    output.state = current_state;
    output.state_name = controller_state_name(current_state);
    output.changed =
        (previous_inlet_open != inlet_open) ||
        (previous_heater_on != heater_on) ||
        (previous_state != current_state);

    return output;
}

